"""Tests for end-to-end pipeline orchestration — PR8."""

from pathlib import Path

import pytest

from contextlens.schemas import (
    CalendarHook,
    ConversationEntities,
    DocumentEntities,
    FailureFlag,
    ImageOutput,
    ImageType,
    QualitySignals,
    ReceiptEntities,
    WhiteboardEntities,
)

ROOT = Path(__file__).resolve().parent.parent
IMG_DIR = ROOT / "data" / "test_images"

# Ensure test images exist (generated by PR7)
pytestmark = pytest.mark.skipif(
    not (IMG_DIR / "img_001.png").exists(),
    reason="Test images not generated yet; run scripts/generate_test_images.py first",
)


# =====================================================================
# Helpers
# =====================================================================

def _process(image_id: str) -> ImageOutput:
    """Process a single test image through the pipeline."""
    from contextlens.pipeline import process_image
    path = IMG_DIR / f"{image_id}.png"
    return process_image(path, image_id=image_id)


# =====================================================================
# Single image — basic output shape
# =====================================================================

class TestSingleImageOutput:
    def test_returns_image_output(self):
        out = _process("img_001")
        assert isinstance(out, ImageOutput)

    def test_image_id_set(self):
        out = _process("img_001")
        assert out.image_id == "img_001"

    def test_type_is_valid_enum(self):
        out = _process("img_001")
        assert isinstance(out.type, ImageType)
        assert out.type != ImageType.UNKNOWN

    def test_type_confidence_in_range(self):
        out = _process("img_001")
        assert 0.0 <= out.type_confidence <= 1.0

    def test_field_confidence_all_in_range(self):
        out = _process("img_001")
        for k, v in out.field_confidence.items():
            assert 0.0 <= v <= 1.0, f"{k}={v} out of [0,1]"

    def test_summary_non_empty(self):
        out = _process("img_001")
        assert len(out.summary) > 0

    def test_quality_signals_present(self):
        out = _process("img_001")
        assert out.quality_signals is not None
        assert isinstance(out.quality_signals, QualitySignals)

    def test_raw_text_non_empty(self):
        out = _process("img_001")
        assert len(out.raw_text) > 0


# =====================================================================
# Receipt — clean (img_001)
# =====================================================================

class TestReceiptClean:
    def test_type_is_receipt(self):
        out = _process("img_001")
        assert out.type == ImageType.RECEIPT

    def test_entities_are_receipt_type(self):
        out = _process("img_001")
        assert isinstance(out.extracted_entities, ReceiptEntities)

    def test_merchant_extracted(self):
        out = _process("img_001")
        assert out.extracted_entities.merchant is not None
        assert len(out.extracted_entities.merchant) > 0

    def test_total_extracted(self):
        out = _process("img_001")
        assert out.extracted_entities.total is not None
        assert out.extracted_entities.total > 0

    def test_items_extracted(self):
        out = _process("img_001")
        assert isinstance(out.extracted_entities.items, list)
        assert len(out.extracted_entities.items) >= 1, (
            "Clean receipt should extract at least one item"
        )

    def test_no_failure_flags(self):
        out = _process("img_001")
        assert out.failure_flags == []

    def test_no_clarification_needed(self):
        out = _process("img_001")
        assert out.needs_clarification is False

    def test_calendar_hook_none(self):
        out = _process("img_001")
        assert out.calendar_hook is None

    def test_high_confidence_on_clean(self):
        out = _process("img_001")
        # Clean image should have all field confidences >= 0.3
        for k, v in out.field_confidence.items():
            assert v >= 0.3, (
                f"Clean receipt field '{k}' has low confidence {v}"
            )


