# =====================================================================
# Adversarial — blurry receipt (img_003)
# =====================================================================

class TestBlurryReceipt:
    def test_blurry_flag_set(self):
        out = _process("img_003")
        assert FailureFlag.BLURRY_IMAGE in out.failure_flags

    def test_quality_signals_show_blurry(self):
        out = _process("img_003")
        assert out.quality_signals.is_blurry is True

    def test_confidence_lower_than_clean(self):
        clean = _process("img_001")
        blurry = _process("img_003")
        # Average confidence should be lower for blurry
        if clean.field_confidence and blurry.field_confidence:
            avg_clean = sum(clean.field_confidence.values()) / len(clean.field_confidence)
            avg_blurry = sum(blurry.field_confidence.values()) / len(blurry.field_confidence)
            assert avg_blurry < avg_clean


