# Adversarial — rotated receipt (img_002)
# =====================================================================

class TestRotatedReceipt:
    def test_rotation_detected(self):
        out = _process("img_002")
        assert out.quality_signals.is_rotated is True

    def test_rotation_flag_set(self):
        out = _process("img_002")
        assert FailureFlag.ROTATION_UNRESOLVED in out.failure_flags

    def test_still_produces_valid_type(self):
        out = _process("img_002")
        assert isinstance(out.type, ImageType)


# =====================================================================
# Batch processing
# =====================================================================

class TestBatchProcessing:
    def test_batch_returns_correct_count(self):
        from contextlens.pipeline import process_batch
        paths = [IMG_DIR / f"img_{i:03d}.png" for i in [1, 5, 8]]
        outputs = process_batch(paths)
        assert len(outputs) == 3

    def test_batch_all_valid_outputs(self):
        from contextlens.pipeline import process_batch
        paths = [IMG_DIR / f"img_{i:03d}.png" for i in [1, 5, 8]]
        outputs = process_batch(paths)
        for out in outputs:
            assert isinstance(out, ImageOutput)
            assert len(out.summary) > 0
            assert out.quality_signals is not None

    def test_batch_with_explicit_ids(self):
        from contextlens.pipeline import process_batch
        paths = [IMG_DIR / "img_001.png", IMG_DIR / "img_005.png"]
        ids = ["test_a", "test_b"]
        outputs = process_batch(paths, image_ids=ids)
        assert outputs[0].image_id == "test_a"
        assert outputs[1].image_id == "test_b"

    def test_batch_mismatched_lengths_raises(self):
        from contextlens.pipeline import process_batch
        with pytest.raises(ValueError):
            process_batch(
                [IMG_DIR / "img_001.png"],
                image_ids=["a", "b"],
            )


