# =====================================================================
# Summary generation
# =====================================================================

class TestSummaryGeneration:
    def test_receipt_summary_contains_merchant(self):
        out = _process("img_001")
        if out.type == ImageType.RECEIPT and out.extracted_entities.merchant:
            assert out.extracted_entities.merchant.lower() in out.summary.lower()

    def test_conversation_summary_mentions_participants(self):
        out = _process("img_006")
        if out.type == ImageType.CONVERSATION:
            assert "conversation" in out.summary.lower()

    def test_document_summary_mentions_kind(self):
        out = _process("img_008")
        if out.type == ImageType.DOCUMENT:
            assert "field" in out.summary.lower()

    def test_whiteboard_summary_mentions_tasks(self):
        out = _process("img_011")
        if out.type == ImageType.WHITEBOARD:
            assert "task" in out.summary.lower() or "whiteboard" in out.summary.lower()


# =====================================================================
# Output serialization
# =====================================================================

class TestOutputSerialization:
    def test_output_to_json(self):
        out = _process("img_001")
        json_str = out.model_dump_json()
        assert len(json_str) > 0

    def test_output_to_dict(self):
        out = _process("img_001")
        d = out.model_dump()
        assert isinstance(d, dict)
        assert "image_id" in d
        assert "type" in d
        assert "field_confidence" in d
        assert "summary" in d

    def test_roundtrip(self):
        out = _process("img_001")
        d = out.model_dump()
        restored = ImageOutput(**d)
        assert restored.image_id == out.image_id
        assert restored.type == out.type
